function bindleftCommonSearchdropdown(instance, fieldName) {
    var vm = instance;    
    if (fieldName == 'WORKCODE') {
        DataService.GetWorkCodes().then((response) => {
            if (response.data.result.length > 0) {
                vm.leftSearchFields[2].listOptions = [];
                response.data.result.forEach(element => {
                    let Obj = {
                        value: `${element.Value}`,
                        name: element.Text
                    }
                    vm.leftSearchFields[2].listOptions.push(Obj);
                });
            }
        });
    }
    if (fieldName == 'STATE') {
        var params = `countryId=223&includeCandaState=true`;
        DataService.GetStateListByCountryId(params).then((response) => {
            if (response.data.result.length > 0) {
                vm.leftSearchFields[3].listOptions = [];
                const StateNames = response.data.result;
                StateNames.forEach(element => {
                    let Obj = {
                        value: `${element.STATE_ID}`,
                        name: element.STATE_NAME
                    }
                    vm.leftSearchFields[3].listOptions.push(Obj);
                });
            }

        });
    }
}


export default { buttons, leftsearchSchema, listActions, bindleftCommonSearchdropdown }; 